INSERT INTO passage_questions (id, passage_id, question_number, question_type, question_text, explanation, correct_choice) VALUES
(232, 78, 1, 'comprehension', 'What role do short-chain fatty acids play in the gut-brain axis, according to the passage?', '第2段落で、短鎖脂肪酸（酪酸やプロピオン酸）は炎症を調節し（modulate inflammation）、血液脳関門の完全性を促進する（foster the integrity of the blood-brain barrier）と述べられている。選択肢4がこの記述に最も合致する。', 4),
(233, 78, 2, 'comprehension', 'Why have clinical trials of probiotic interventions for mental health produced inconsistent results?', '第4段落で、結果のばらつきの原因として「the staggering variability of individual microbiomes」（個人のマイクロバイオームの驚異的なばらつき）が挙げられ、遺伝、食事、抗生物質への曝露、出生時の分娩様式などの要因が述べられている。選択肢2がこの説明に最も合致する。', 2),
(234, 78, 3, 'fill_in_blank', 'Choose the best option to fill in the blank [BLANK] in the passage.', '空所は第4段落の最後にあり、「This inherent complexity makes it arduous to devise」（この固有の複雑さが～を考案することを困難にしている）に続く。個人のマイクロバイオームの多様性が問題であるという文脈から、選択肢3「standardized treatments that are universally effective across diverse patient populations」（多様な患者集団に普遍的に有効な標準化された治療法）が最も適切。', 3);
INSERT INTO question_choices (question_id, choice_number, choice_text) VALUES
(232, 1, 'They serve as the primary energy source for neurons in the cerebral cortex, replacing glucose during periods of fasting.'),
(232, 2, 'They directly stimulate the vagus nerve to increase heart rate and improve blood circulation to the brain.'),
(232, 3, 'They break down neurotransmitters in the gut, preventing excessive serotonin from reaching the brain.'),
(232, 4, 'They help regulate inflammation and support the protective function of the blood-brain barrier.'),
(233, 1, 'Pharmaceutical companies have deliberately suppressed positive results to protect their existing antidepressant drug revenues.'),
(233, 2, 'Each person''s gut microbiome is uniquely shaped by factors such as genetics, diet, and antibiotic history, making standardized interventions unreliable.'),
(233, 3, 'The probiotic organisms used in trials are unable to survive the acidic environment of the human stomach.'),
(233, 4, 'Researchers have used identical methodologies across all studies, leaving no room for variation in outcomes.'),
(234, 1, 'affordable probiotic supplements that can be mass-produced and distributed to developing nations'),
(234, 2, 'laboratory environments sterile enough to study microbial interactions without contamination'),
(234, 3, 'standardized treatments that are universally effective across diverse patient populations'),
(234, 4, 'diagnostic tools capable of distinguishing between beneficial and harmful bacterial strains');
